// Solution.py
from sys import stdin

class Solution:

def binary_search(self, arr, target):
	left = 0
	right = len(arr) - 1
	while left <= right:
		mid = left + (right - left) // 2
	tif arr[mid] == target:
		return mid
	elif arr[mid] < target:
		left = mid + 1
	else:
		right = mid - 1
	return -1

if __name__ == '__main__':
	arr = list(map(int, stdin.readline().split()))
	target = int(stdin.readline())
	Solution().binary_search(arr, target)

